// src/components/AnnotationCanvas.js
import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Arrow,
  Transformer,
  Label,
  Tag,
  Text,
  Path
} from 'react-konva';
import './AnnotationCanvas.css';
import { useSegmentation } from '../utils/segmentationLogic';

function flattenPoints(pts) {
  return pts.flatMap(p => [p.x, p.y]);
}

function polygonToPath(outer, holes) {
  let path = 'M ' + outer[0].x + ' ' + outer[0].y + ' ';
  for (let i = 1; i < outer.length; i++) {
    path += 'L ' + outer[i].x + ' ' + outer[i].y + ' ';
  }
  path += 'Z ';
  if (holes && holes.length > 0) {
    holes.forEach(hole => {
      if (hole.length > 0) {
        path += 'M ' + hole[0].x + ' ' + hole[0].y + ' ';
        for (let i = 1; i < hole.length; i++) {
          path += 'L ' + hole[i].x + ' ' + hole[i].y + ' ';
        }
        path += 'Z ';
      }
    });
  }
  return path;
}

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool,
  scale,
  onWheelZoom,
  activeLabelColor,
  labelClasses,
  onFinishShape,
  onDeleteAnnotation,
  activeLabel,
  segmentationType,
  panopticOption,
  enableSegmentation
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);
  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [tempPolyline, setTempPolyline] = useState([]);
  const [drawingPolyline, setDrawingPolyline] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);
  const [tempPointPoints, setTempPointPoints] = useState([]);
  const [drawingPoint, setDrawingPoint] = useState(false);
  const [selectedAnnotationIndex, setSelectedAnnotationIndex] = useState(null);
  const transformerRef = useRef(null);
  const shapeRefs = useRef([]);

  // Use segmentation hook if segmentation is enabled
  const segmentation = enableSegmentation ? useSegmentation(activeLabel, activeLabelColor, konvaImg, annotations, onAnnotationsChange, onFinishShape) : null;

  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      setDims({
        width: containerRef.current.offsetWidth,
        height: containerRef.current.offsetHeight,
      });
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (!fileUrl) return;
    const img = new window.Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  function getGroupPos(evt) {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  }

  function startBox(pos) {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  }
  function updateBox(pos) {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  }
  function finalizeBox() {
    if (!newBox) return;
    const newAnn = {
      type: 'bbox',
      ...newBox,
      label: activeLabel,
      color: activeLabelColor,
    };
    onAnnotationsChange([...annotations, newAnn]);
    setNewBox(null);
    onFinishShape && onFinishShape();
  }
  function addPolygonPoint(pos) {
    setTempPoints(prev => [...prev, pos]);
    setDrawingPolygon(true);
  }
  function finalizePolygon() {
    if (tempPoints.length >= 3) {
      const newAnn = {
        type: 'polygon',
        points: tempPoints,
        label: activeLabel,
        color: activeLabelColor,
      };
      onAnnotationsChange([...annotations, newAnn]);
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape && onFinishShape();
  }
  function addPolylinePoint(pos) {
    setTempPolyline(prev => [...prev, pos]);
    setDrawingPolyline(true);
  }
  function finalizePolyline() {
    if (tempPolyline.length >= 2) {
      const newAnn = {
        type: 'polyline',
        points: tempPolyline,
        label: activeLabel,
        color: activeLabelColor,
      };
      onAnnotationsChange([...annotations, newAnn]);
    }
    setTempPolyline([]);
    setDrawingPolyline(false);
    onFinishShape && onFinishShape();
  }
  function addPointToPoints(pos) {
    setTempPointPoints(prev => [...prev, pos]);
    setDrawingPoint(true);
  }
  function finalizePoint() {
    if (tempPointPoints.length > 0) {
      const newAnn = {
        type: 'points',
        points: tempPointPoints,
        label: activeLabel,
        color: activeLabelColor,
      };
      onAnnotationsChange([...annotations, newAnn]);
    }
    setTempPointPoints([]);
    setDrawingPoint(false);
    onFinishShape && onFinishShape();
  }
  function startEllipse(pos) {
    setNewEllipse({
      type: 'ellipse',
      x: pos.x,
      y: pos.y,
      radiusX: 0,
      radiusY: 0,
      rotation: 0,
      label: activeLabel,
      color: activeLabelColor,
    });
  }
  function updateEllipse(pos) {
    if (!newEllipse) return;
    const rx = Math.abs(pos.x - newEllipse.x);
    const ry = Math.abs(pos.y - newEllipse.y);
    setNewEllipse({
      ...newEllipse,
      radiusX: rx,
      radiusY: ry,
    });
  }
  function finalizeEllipse() {
    if (!newEllipse) return;
    onAnnotationsChange([...annotations, newEllipse]);
    setNewEllipse(null);
    onFinishShape && onFinishShape();
  }

  function handleWheel(evt) {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  }

  function handleContextMenu(evt) {
    evt.evt.preventDefault();
    if (selectedTool === 'polygon' && drawingPolygon && tempPoints.length > 0) {
      setTempPoints(prev => prev.slice(0, -1));
    }
    else if (selectedTool === 'polyline' && drawingPolyline && tempPolyline.length > 0) {
      setTempPolyline(prev => prev.slice(0, -1));
    }
    else if (selectedTool === 'point' && drawingPoint && tempPointPoints.length > 0) {
      setTempPointPoints(prev => prev.slice(0, -1));
    }
    else if (selectedTool === 'segmentation' && enableSegmentation && segmentation) {
      if (segmentationType === 'instance' && segmentation.drawingInstancePolygon && segmentation.tempInstancePoints.length > 0) {
        segmentation.removeLastInstancePoint();
      } else if (segmentationType === 'semantic' && segmentation.drawingSemanticPolygon && segmentation.tempSemanticPoints.length > 0) {
        segmentation.removeLastSemanticPoint();
      } else if (segmentationType === 'panoptic') {
        if (panopticOption === 'instance' && segmentation.drawingInstancePolygon && segmentation.tempInstancePoints.length > 0) {
          segmentation.removeLastInstancePoint();
        } else if (panopticOption === 'semantic' && segmentation.drawingSemanticPolygon && segmentation.tempSemanticPoints.length > 0) {
          segmentation.removeLastSemanticPoint();
        }
      }
    }
  }

  function handleMouseDown(evt) {
    if (selectedTool === 'move') return;
    const pos = getGroupPos(evt);
    if (!pos) return;
    if (selectedTool === 'bbox') {
      startBox(pos);
    } else if (selectedTool === 'polygon') {
      addPolygonPoint(pos);
    } else if (selectedTool === 'polyline') {
      addPolylinePoint(pos);
    } else if (selectedTool === 'point') {
      addPointToPoints(pos);
    } else if (selectedTool === 'ellipse') {
      startEllipse(pos);
    } else if (selectedTool === 'segmentation' && enableSegmentation && segmentation) {
      if (segmentationType === 'instance') {
        segmentation.addInstancePolygonPoint(pos);
      } else if (segmentationType === 'semantic') {
        segmentation.addSemanticPolygonPoint(pos);
      } else if (segmentationType === 'panoptic') {
        if (panopticOption === 'instance') {
          segmentation.addInstancePolygonPoint(pos);
        } else if (panopticOption === 'semantic') {
          segmentation.addSemanticPolygonPoint(pos);
        }
      }
    }
  }

  function handleMouseMove(evt) {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getGroupPos(evt);
      if (pos) updateEllipse(pos);
    }
  }

  function handleMouseUp() {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      finalizeEllipse();
    }
  }

  function handleDblClick() {
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    } else if (selectedTool === 'polyline' && drawingPolyline) {
      finalizePolyline();
    } else if (selectedTool === 'point' && drawingPoint) {
      finalizePoint();
    } else if (selectedTool === 'segmentation' && enableSegmentation && segmentation) {
      if (segmentationType === 'instance' && segmentation.drawingInstancePolygon) {
        segmentation.finalizeInstancePolygon();
      } else if (segmentationType === 'semantic' && segmentation.drawingSemanticPolygon) {
        segmentation.finalizeSemanticPolygon();
      } else if (segmentationType === 'panoptic') {
        if (panopticOption === 'instance' && segmentation.drawingInstancePolygon) {
          segmentation.finalizeInstancePolygon();
        } else if (panopticOption === 'semantic' && segmentation.drawingSemanticPolygon) {
          segmentation.finalizeSemanticPolygon();
        }
      }
    }
  }

  useEffect(() => {
    const onCancelAnnotation = () => {
      setNewBox(null);
      setTempPoints([]);
      setDrawingPolygon(false);
      setTempPolyline([]);
      setDrawingPolyline(false);
      setNewEllipse(null);
      setTempPointPoints([]);
      setDrawingPoint(false);
      // Segmentation cancellation can be handled in the segmentation hook if needed.
    };
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () => window.removeEventListener('cancel-annotation', onCancelAnnotation);
  }, []);

  useEffect(() => {
    const tr = transformerRef.current;
    if (!tr) return;
    if (selectedAnnotationIndex == null) {
      tr.nodes([]);
      return;
    }
    const node = shapeRefs.current[selectedAnnotationIndex];
    if (node) {
      tr.nodes([node]);
      tr.getLayer().batchDraw();
    } else {
      tr.nodes([]);
    }
  }, [selectedAnnotationIndex, annotations]);

  const handleTransformEnd = () => {
    if (selectedAnnotationIndex == null) return;
    const shapeNode = shapeRefs.current[selectedAnnotationIndex];
    if (!shapeNode) return;
    const ann = annotations[selectedAnnotationIndex];
    const scaleX = shapeNode.scaleX();
    const scaleY = shapeNode.scaleY();
    const offsetX = shapeNode.x();
    const offsetY = shapeNode.y();
    let updatedAnn = { ...ann };
    if (ann.type === 'bbox') {
      const newWidth = shapeNode.width() * scaleX;
      const newHeight = shapeNode.height() * scaleY;
      updatedAnn.x = offsetX;
      updatedAnn.y = offsetY;
      updatedAnn.width = newWidth;
      updatedAnn.height = newHeight;
    } else if (ann.type === 'ellipse') {
      const newRadiusX = (shapeNode.width() / 2) * scaleX;
      const newRadiusY = (shapeNode.height() / 2) * scaleY;
      updatedAnn.x = offsetX;
      updatedAnn.y = offsetY;
      updatedAnn.radiusX = newRadiusX;
      updatedAnn.radiusY = newRadiusY;
    }
    shapeNode.scaleX(1);
    shapeNode.scaleY(1);
    shapeNode.x(0);
    shapeNode.y(0);
    const updatedAll = [...annotations];
    updatedAll[selectedAnnotationIndex] = updatedAnn;
    onAnnotationsChange(updatedAll);
  };

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
        onContextMenu={handleContextMenu}
      >
        <Layer>
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'}
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => setImagePos({ x: e.target.x(), y: e.target.y() })}
          >
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}
            {annotations.map((ann, i) => {
              const annColor = ann.color || activeLabelColor;
              const fillColor = annColor + '55';
              if (ann.type === 'bbox') {
                return (
                  <React.Fragment key={i}>
                    <Rect
                      ref={(node) => (shapeRefs.current[i] = node)}
                      x={ann.x}
                      y={ann.y}
                      width={ann.width}
                      height={ann.height}
                      fill={fillColor}
                      stroke={annColor}
                      strokeWidth={2 / scale}
                      draggable
                      onDragEnd={(e) => handleTransformEnd()}
                      onClick={(e) => { if (selectedTool === 'move') setSelectedAnnotationIndex(i); }}
                    />
                  </React.Fragment>
                );
              } else if (ann.type === 'ellipse') {
                return (
                  <React.Fragment key={i}>
                    <Ellipse
                      ref={(node) => (shapeRefs.current[i] = node)}
                      x={ann.x}
                      y={ann.y}
                      radiusX={ann.radiusX}
                      radiusY={ann.radiusY}
                      fill={fillColor}
                      stroke={annColor}
                      strokeWidth={2 / scale}
                      draggable
                      onDragEnd={(e) => handleTransformEnd()}
                      onClick={(e) => { if (selectedTool === 'move') setSelectedAnnotationIndex(i); }}
                    />
                  </React.Fragment>
                );
              } else if (ann.type === 'polyline') {
                const pts = flattenPoints(ann.points);
                return (
                  <React.Fragment key={i}>
                    <Group draggable onDragEnd={(e) => handleTransformEnd()}>
                      <Line
                        points={pts}
                        stroke={annColor}
                        strokeWidth={2 / scale}
                        closed={false}
                      />
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={4 / scale}
                          fill="#fff"
                          stroke={annColor}
                          strokeWidth={1 / scale}
                          draggable
                          onDragEnd={(ev) => { }}
                        />
                      ))}
                      <Arrow
                        points={[ann.points[1]?.x, ann.points[1]?.y, ann.points[0]?.x, ann.points[0]?.y]}
                        fill={annColor}
                        stroke={annColor}
                        strokeWidth={2 / scale}
                        pointerLength={10 / scale}
                        pointerWidth={8 / scale}
                      />
                    </Group>
                  </React.Fragment>
                );
              } else if (ann.type === 'polygon') {
                if (ann.holes && ann.holes.length > 0) {
                  const pathData = polygonToPath(ann.points, ann.holes);
                  return (
                    <React.Fragment key={i}>
                      <Group draggable onDragEnd={(e) => handleTransformEnd()}>
                        <Path
                          data={pathData}
                          fill={fillColor}
                          stroke={annColor}
                          strokeWidth={2 / scale}
                          fillRule="evenodd"
                        />
                      </Group>
                    </React.Fragment>
                  );
                } else {
                  const pts = flattenPoints(ann.points);
                  return (
                    <React.Fragment key={i}>
                      <Group draggable onDragEnd={(e) => handleTransformEnd()}>
                        <Line
                          points={pts}
                          fill={fillColor}
                          stroke={annColor}
                          strokeWidth={2 / scale}
                          closed
                        />
                        {ann.points.map((pt, idx) => (
                          <Circle
                            key={idx}
                            x={pt.x}
                            y={pt.y}
                            radius={4 / scale}
                            fill="#fff"
                            stroke={annColor}
                            strokeWidth={1 / scale}
                            draggable
                            onDragEnd={(ev) => { }}
                          />
                        ))}
                        <Arrow
                          points={[ann.points[1]?.x, ann.points[1]?.y, ann.points[0]?.x, ann.points[0]?.y]}
                          fill={annColor}
                          stroke={annColor}
                          strokeWidth={2 / scale}
                          pointerLength={10 / scale}
                          pointerWidth={8 / scale}
                        />
                      </Group>
                    </React.Fragment>
                  );
                }
              } else if (ann.type === 'points') {
                return (
                  <React.Fragment key={i}>
                    <Group draggable onDragEnd={(e) => handleTransformEnd()}>
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={6 / scale}
                          fill={annColor}
                          draggable
                          onDragEnd={(e) => { }}
                        />
                      ))}
                    </Group>
                  </React.Fragment>
                );
              }
              return null;
            })}

            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={activeLabelColor + '55'}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {drawingPolygon && selectedTool === 'polygon' && (
              <>
                {tempPoints.length > 1 && (
                  <Line
                    points={flattenPoints([...tempPoints, tempPoints[0]])}
                    fill={activeLabelColor + '55'}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed
                  />
                )}
                {tempPoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {drawingPolyline && selectedTool === 'polyline' && (
              <>
                {tempPolyline.length > 1 && (
                  <Line
                    points={flattenPoints(tempPolyline)}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed={false}
                  />
                )}
                {tempPolyline.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {newEllipse && selectedTool === 'ellipse' && (
              <Ellipse
                x={newEllipse.x}
                y={newEllipse.y}
                radiusX={newEllipse.radiusX}
                radiusY={newEllipse.radiusY}
                rotation={newEllipse.rotation}
                fill={activeLabelColor + '55'}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {drawingPoint && selectedTool === 'point' && (
              <>
                {tempPointPoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {enableSegmentation && selectedTool === 'segmentation' && segmentation && segmentationType === 'instance' && segmentation.drawingInstancePolygon && (
              <>
                {segmentation.tempInstancePoints.length > 1 && (
                  <Line
                    points={flattenPoints([...segmentation.tempInstancePoints, segmentation.tempInstancePoints[0]])}
                    fill={activeLabelColor + '55'}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed
                  />
                )}
                {segmentation.tempInstancePoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {enableSegmentation && selectedTool === 'segmentation' && segmentation && segmentationType === 'semantic' && segmentation.drawingSemanticPolygon && (
              <>
                {segmentation.tempSemanticPoints.length > 1 && (
                  <Line
                    points={flattenPoints([...segmentation.tempSemanticPoints, segmentation.tempSemanticPoints[0]])}
                    fill={activeLabelColor + '55'}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed
                  />
                )}
                {segmentation.tempSemanticPoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {enableSegmentation && selectedTool === 'segmentation' && segmentation && segmentationType === 'panoptic' && panopticOption === 'instance' && segmentation.drawingInstancePolygon && (
              <>
                {segmentation.tempInstancePoints.length > 1 && (
                  <Line
                    points={flattenPoints([...segmentation.tempInstancePoints, segmentation.tempInstancePoints[0]])}
                    fill={activeLabelColor + '55'}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed
                  />
                )}
                {segmentation.tempInstancePoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {enableSegmentation && selectedTool === 'segmentation' && segmentation && segmentationType === 'panoptic' && panopticOption === 'semantic' && segmentation.drawingSemanticPolygon && (
              <>
                {segmentation.tempSemanticPoints.length > 1 && (
                  <Line
                    points={flattenPoints([...segmentation.tempSemanticPoints, segmentation.tempSemanticPoints[0]])}
                    fill={activeLabelColor + '55'}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed
                  />
                )}
                {segmentation.tempSemanticPoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}
          </Group>

          <Transformer
            ref={transformerRef}
            rotateEnabled={false}
            anchorSize={8}
            borderDash={[6, 2]}
            onTransformEnd={handleTransformEnd}
            onDragEnd={handleTransformEnd}
          />
        </Layer>
      </Stage>
    </div>
  );
}

// A small Konva Label to let the user delete a selected annotation
function DeleteLabel({ annotation, scale, onDelete, color }) {
  return (
    <Label
      x={annotation.x}
      y={annotation.y - 20 / scale}
      scaleX={1 / scale}
      scaleY={1 / scale}
      onClick={(e) => { e.cancelBubble = true; onDelete(); }}
    >
      <Tag fill={color || 'red'} opacity={0.8} cornerRadius={4} />
      <Text text="Delete" fill="#fff" padding={5} fontSize={14} />
    </Label>
  );
}
